(() => {
  const utils = window.IKSASS || {};
  const escapeHtml = utils.escapeHtml || ((value) => String(value || ''));
  const resolveUrl = utils.resolveUrl || ((value) => value);

  const root = document.querySelector('[data-home-testi]');
  const track = document.querySelector('[data-home-testi-track]');
  const dotsWrap = document.querySelector('[data-home-testi-dots]');
  const btnPrev = document.querySelector('[data-home-testi-prev]');
  const btnNext = document.querySelector('[data-home-testi-next]');
  if (!root || !track || !dotsWrap || !btnPrev || !btnNext) return;

  let items = [];
  let index = 0;
  let startX = 0;
  let dragging = false;

  function clamp(value) {
    if (!items.length) return 0;
    return Math.max(0, Math.min(value, items.length - 1));
  }

  function renderDots() {
    dotsWrap.innerHTML = items.map((_, idx) => {
      const active = idx === index ? ' is-active' : '';
      return `<button class="testi-dot${active}" type="button" aria-label="Slide ${idx + 1}" data-idx="${idx}"></button>`;
    }).join('');
  }

  function update() {
    index = clamp(index);
    track.style.transform = `translate3d(${-index * 100}%, 0, 0)`;
    btnPrev.disabled = index === 0;
    btnNext.disabled = index === items.length - 1;
    dotsWrap.querySelectorAll('.testi-dot').forEach((dot, idx) => {
      dot.classList.toggle('is-active', idx === index);
    });
  }

  function render() {
    if (!items.length) {
      track.innerHTML = '<div class="testi-empty">Testimoni alumni akan ditampilkan di sini.</div>';
      dotsWrap.innerHTML = '';
      btnPrev.disabled = true;
      btnNext.disabled = true;
      return;
    }

    track.innerHTML = items.map((item) => {
      const name = escapeHtml(item.name || 'Alumni IKSASS');
      const role = escapeHtml(item.role || '');
      const location = escapeHtml(item.location || '');
      const quote = escapeHtml(item.quote || '');
      return `
        <article class="card testi-card" role="group" aria-label="Testimoni">
          <div class="testi-quote">“${quote}”</div>
          <div class="testi-meta">
            <div class="testi-name">${name}</div>
            <div class="testi-role">${role}${role && location ? ' • ' : ''}${location}</div>
          </div>
        </article>
      `;
    }).join('');

    renderDots();
    update();
  }

  function go(nextIndex) {
    index = clamp(nextIndex);
    update();
  }

  function onPointerDown(event) {
    if (items.length <= 1) return;
    dragging = true;
    startX = (event.touches && event.touches[0]) ? event.touches[0].clientX : event.clientX;
  }

  function onPointerUp(event) {
    if (!dragging) return;
    dragging = false;
    const endX = (event.changedTouches && event.changedTouches[0]) ? event.changedTouches[0].clientX : event.clientX;
    const deltaX = endX - startX;
    if (deltaX > 40) go(index - 1);
    else if (deltaX < -40) go(index + 1);
  }

  function init() {
    fetch(resolveUrl('assets/data/testimonials.json'), { cache: 'no-store' })
      .then((response) => (response.ok ? response.json() : Promise.reject(new Error(`testimonials.json: ${response.status}`))))
      .then((json) => {
        items = Array.isArray(json.items) ? json.items : [];
        index = 0;
        render();
      })
      .catch((error) => {
        console.error('[home-testimonials] gagal memuat data:', error);
        items = [];
        render();
      });
  }

  btnPrev.addEventListener('click', () => go(index - 1));
  btnNext.addEventListener('click', () => go(index + 1));
  dotsWrap.addEventListener('click', (event) => {
    const btn = event.target.closest('[data-idx]');
    if (!btn) return;
    const nextIndex = Number(btn.getAttribute('data-idx'));
    if (Number.isFinite(nextIndex)) go(nextIndex);
  });

  const viewport = root.querySelector('.testi__viewport');
  viewport.addEventListener('mousedown', onPointerDown);
  viewport.addEventListener('mouseup', onPointerUp);
  viewport.addEventListener('mouseleave', onPointerUp);
  viewport.addEventListener('touchstart', onPointerDown, { passive: true });
  viewport.addEventListener('touchend', onPointerUp, { passive: true });

  init();
})();
